/**
 * =====================
 */
/**
 * GLOBALS
 */
/**
 * =====================
 */
// =====================
// SPAWN VASES
// =====================
function spawnVases () {
    locations = tiles.getTilesByType(assets.tile`baseTransparency16`)
    // create 3 vases
    vase1 = sprites.create(assets.image`vpot`, SpriteKind.Food)
    vase2 = sprites.create(assets.image`vpot`, SpriteKind.Food)
    vase3 = sprites.create(assets.image`vpot`, SpriteKind.Food)
    // place them in different tiles
    tiles.placeOnTile(vase1, locations[1])
    tiles.placeOnTile(vase2, locations[5])
    tiles.placeOnTile(vase3, locations[9])
    // randomly choose which vase has key
    choice = randint(1, 3)
    if (choice == 1) {
        keyVase = vase1
    }
    if (choice == 2) {
        keyVase = vase2
    }
    if (choice == 3) {
        keyVase = vase3
    }
}
// =====================
// BREAK VASE
// =====================
sprites.onOverlap(SpriteKind.Player, SpriteKind.Food, function (player2, vase) {
    // check if this is the key vase
    if (vase == keyVase) {
        keyFound = true
        game.showLongText("You found the key!", DialogLayout.Center)
        spawnChest()
    } else {
        game.showLongText("Nothing useful...", DialogLayout.Bottom)
    }
    vase.destroy()
})
// =====================
// SPAWN CHEST
// =====================
function spawnChest () {
    chest = sprites.create(assets.image`chest`, SpriteKind.Projectile)
    locations2 = tiles.getTilesByType(assets.tile`baseTransparency16`)
    tiles.placeOnTile(chest, locations2[locations2.length - 1])
}
// =====================
// CHEST → WIN
// =====================
sprites.onOverlap(SpriteKind.Player, SpriteKind.Projectile, function (player2, chest) {
    if (keyFound) {
        game.showLongText("Level Complete!", DialogLayout.Center)
        game.over(true)
    }
})
let locations2: tiles.Location[] = []
let chest: Sprite = null
let keyFound = false
let keyVase: Sprite = null
let choice = 0
let vase3: Sprite = null
let vase2: Sprite = null
let vase1: Sprite = null
let locations: tiles.Location[] = []
// =====================
// LOAD MAP (F1)
// =====================
tiles.setTilemap(tilemap`F1`)
// =====================
// CREATE HERO
// =====================
let hero = sprites.create(assets.image`hero`, SpriteKind.Player)
// place hero in center
let tilesList = tiles.getTilesByType(assets.tile`baseTransparency16`)
let centerTile = tilesList[Math.floor(tilesList.length / 2)]
tiles.placeOnTile(hero, centerTile)
// movement + camera
controller.moveSprite(hero)
scene.cameraFollowSprite(hero)
// =====================
// START GAME
// =====================
spawnVases()

